package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Date;

public class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateTypeMock;

    @BeforeEach
    public void setUp() throws Exception {
        dateTypeMock = mock(DefaultDateTypeAdapter.DateType.class);

        // Use reflection to get the private constructor
        Class<DefaultDateTypeAdapter> clazz = DefaultDateTypeAdapter.class;
        var constructors = clazz.getDeclaredConstructors();
        // Find the constructor with parameters (DateType<T>, String)
        var constructor = clazz.getDeclaredConstructor(DefaultDateTypeAdapter.DateType.class, String.class);
        constructor.setAccessible(true);
        adapter = (DefaultDateTypeAdapter<Date>) constructor.newInstance(dateTypeMock, "yyyy-MM-dd");
    }

    @Test
    public void testRead_NullToken_ReturnsNull() throws IOException {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.NULL);

        Date result = adapter.read(in);

        verify(in).nextNull();
        assertNull(result);
    }

    @Test
    public void testRead_ValidDate_DeserializeCalled() throws Exception {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.STRING);

        // Spy adapter to mock private method deserializeToDate using reflection
        DefaultDateTypeAdapter<Date> spyAdapter = Mockito.spy(adapter);

        Date expectedDate = new Date();

        // Use reflection to get the private method deserializeToDate
        Method deserializeToDateMethod = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeToDateMethod.setAccessible(true);

        // Mock the private method by using doAnswer with reflection invoke
        doAnswer(invocation -> expectedDate).when(spyAdapter).read(any());

        // Instead of mocking read(), we will mock deserializeToDate via reflection proxy
        // Since Mockito cannot mock private methods directly, we use a workaround:
        // Replace the private method with a proxy by subclassing or using reflection
        // Here we simulate by calling the real read() but intercept deserializeToDate call

        // To do this properly, we replace the private method via reflection with a proxy:
        // But since it's complicated, we use the following approach:

        // Use reflection to override deserializeToDate method by creating a subclass

        // Alternatively, set the dateTypeMock to return expectedDate when deserialize is called
        when(dateTypeMock.deserialize(expectedDate)).thenReturn(expectedDate);

        // Instead of mocking deserializeToDate, we invoke it directly and then call dateTypeMock.deserialize
        // So call deserializeToDate method reflectively
        Date deserializedDate = (Date) deserializeToDateMethod.invoke(spyAdapter, in);

        // Verify that deserializedDate is not null (we cannot mock it, so just check not null)
        assertNotNull(deserializedDate);

        // Now call read(), but since we cannot mock deserializeToDate, we do a partial test
        // We create a spy adapter that calls real method but intercepts deserializeToDate by reflection

        // To fully test, we can create a subclass that overrides deserializeToDate as protected

        // For the purpose of this fix, we just call read() and verify dateTypeMock.deserialize is called with any Date

        // Use spyAdapter.read(in)
        // But since deserializeToDate is private and cannot be mocked directly, we verify interaction with dateTypeMock

        // Call read()
        Date result = spyAdapter.read(in);

        // Verify dateTypeMock.deserialize called with a Date (cannot check exact date)
        verify(dateTypeMock).deserialize(any(Date.class));

        // Assert result is not null
        assertNotNull(result);
    }
}
